module	compressor42(
input	A,
input	B,
input	C,
input	D,
input	cin,
output	S,
output	carry,
output	cout
);
wire	AB;
  assign	S=AxBxCxD^cin;
wire	AxorB;
  assign	carry=(AB&CD)|(AxorB&CxorD)|((AxBxCxD)&cin);
wire	CD;
  assign	cout=AB|CD;
wire	CxorD;
  assign	CxorD=C^D;
wire	AxBxCxD=AxorB^CxorD;
  assign	CD=C&D;
  assign	AxorB=A^B;
  assign	AB=A&B;
endmodule
